Method.Source:
/// <summary>
/// Chain of command for validateWrite to prevent UI editing of fully delivered lines.
/// Note: Parameter default values must be omitted in the extension method.
/// </summary>
public boolean validateWrite(boolean _collectMessages)
{

    boolean ret = next validateWrite(_collectMessages);


    if (ret && this.RecId != 0)
    {

        if (this.isFormDataSource())
        {

            if (this.RemainSalesPhysical == 0 && this.SalesQty > 0)
            {
                ret = checkFailed(strFmt("Sales order %1, Line %2 is fully delivered and cannot be edited.", this.SalesId, this.LineNum));
            }
        }
    }

    return ret;
}
